const arrayData = {{workflowparams:arrayData}};
const allData = arrayData[0];
const unique = `${allData.create_user || ""}_${Date.now()}`;

return {
  unique
};

const arrayData = {{workflowparams:arrayData}}
const currentIndexRaw = {{node:get_cache_node_OMu4rhrM.data}}
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0
const saveAs = {{workflowparams:saveAs}}
const pageStatus = {{workflowparams:pageStatus}}

let data = arrayData[index];
let invalidMessage = "";

// Validation: For saveAs "Completed", at least one item must have putaway_qty > 0
if (saveAs === "Completed") {
  const hasPutawayQty = data.table_putaway_item && data.table_putaway_item.length > 0 &&
    data.table_putaway_item.some(item => item.putaway_qty > 0);

  if (!hasPutawayQty) {
    invalidMessage = "Cannot complete putaway. At least one item must have putaway quantity greater than 0.";
  }
}

if (saveAs !== "Cancelled") {
  if (saveAs === "Draft") {
    if (
      data.to_id_type !== -9999 &&
      (!data.to_id ||
        data.to_id === null ||
        data.to_id === "")
    ) {
      data.to_id = "draft";
    }
  } else {
    if (
      data.to_id_type !== -9999 &&
      (!data.to_id ||
        data.to_id === null ||
        data.to_id === "" ||
        data.to_status === "Draft")
    ) {
      data.to_id = "issued";
    }
  }
}

let updatedStatus = {{workflowparams:saveAs}}
if (saveAs === "Completed" && pageStatus === "Add") {
  updatedStatus = "Created"
}

return {
  data,
  updatedStatus,
  nextIndex: index + 1,
  invalidMessage,
  isInvalid: invalidMessage === "" ? 0 : 1
}

return {
  required_fields: JSON.stringify([
      { name: "plant_id", label: "Plant" },
      { name: "to_id", label: "Transfer Order No" },
      { name: "ref_doc_type", label: "Reference Document Type" },
      {
        name: "table_putaway_item",
        label: "Putaway Items",
        isArray: true,
        arrayType: "object",
        arrayFields: [],
      },
]),
  data: JSON.stringify({
    plant_id: {{node:code_node_kku8SAT9.data.data.plant_id}},
    to_id: {{node:code_node_kku8SAT9.data.data.to_id}},
    ref_doc_type: {{node:code_node_kku8SAT9.data.data.ref_doc_type}},
    table_putaway_item: {{node:code_node_kku8SAT9.data.data.table_putaway_item}},
  })
}

let data = {{node:code_node_kku8SAT9.data.data}}

// Helper function to format qty and price fields to 3 decimal places
const formatNumber = (value) => {
  if (value === null || value === undefined || value === "") return 0;
  return parseFloat(value).toFixed(3);
};
// Format qty fields in table_putaway_item
if (data.table_putaway_item && data.table_putaway_item.length > 0) {
  data.table_putaway_item = data.table_putaway_item.map(item => ({
    ...item,
    received_qty: formatNumber(item.received_qty),
    qty_to_putaway: formatNumber(item.qty_to_putaway),
    putaway_qty: formatNumber(item.putaway_qty),
    pending_process_qty: formatNumber(item.pending_process_qty),
  }));
}

// Format qty fields in table_putaway_records if exists
if (data.table_putaway_records && data.table_putaway_records.length > 0) {
  data.table_putaway_records = data.table_putaway_records.map(item => ({
    ...item,
    store_in_qty: formatNumber(item.store_in_qty),
  }));
}

return {
  data
}

const pageStatus = {{workflowparams:pageStatus}}

let putawayData = {{node:code_node_kku8SAT9.data.data}}

if (pageStatus === 'Add') {
  const rawData = {{node:add_node_sjzNkA59.data}}
  putawayData = rawData[0]
  putawayData.table_putaway_item = {{node:search_node_hrs91pu9.data.data}}
}

return {
  putawayData
}

